INSERT INTO `articles` (`id`, `title`, `category`, `author`, `excerpt`, `full_text`, `created_at`, `img`) VALUES
(6, '\"МЫ СОБРАЛИ 500 ПОДАРКОВ ДЛЯ ДЕТЕЙ-СИРОТ\"', 'ОБЩЕСТВО', 'Анна Сидорова', 'Благотворительная акция «Тепло на Рождество» собрала рекордное количество подарков для детских домов региона.', 'В Рязани завершилась масштабная благотворительная акция «Тепло на Рождество». За две недели горожане собрали более 500 подарков для воспитанников детских домов и интернатов региона. Это рекордный результат за всю историю проведения инициативы: в прошлом году было собрано 320 наборов.\r\n\r\nОрганизаторы акции — волонтёрское движение «Рязань помогает» при поддержке городской администрации — заранее определили, что именно нужно детям. Вместо случайных игрушек и сладостей, которые часто остаются невостребованными, в 2025 году был выбран **персонализированный подход**: каждому ребёнку от 3 до 17 лет в четырёх учреждениях составили индивидуальный список желаний.\r\n\r\n«Мы не просто дарим игрушки — мы дарим внимание, заботу и уверенность, что о них помнят. Когда ребёнок видит, что его имя написано на коробке, и внутри именно то, о чём он мечтал — это меняет всё», — говорит Ольга Кузнецова, координатор акции.\r\nКаждый подарочный набор включал три части: новогоднюю игрушку или книгу, набор канцелярии (тетради, ручки, краски) и тёплый предмет одежды — шапку, перчатки или свитер. Особое внимание уделили детям с ОВЗ: для них подготовили сенсорные игрушки, мягкие пледы и обучающие материалы.\r\n\r\nПункты сбора работали в пяти точках города: ТЦ «Премьер», библиотеке им. Горького, на площади Ленина, в молодёжном центре «Ровесник» и у входа в парк «Дружба». Горожане приносили не только готовые подарки, но и участвовали в упаковке. Более 120 волонтёров ежедневно с 9 до 20 часов принимали, сортировали и фасовали дары.\r\n\r\nСреди участников — школьники, студенты, сотрудники предприятий и даже пенсионеры. Ученики 8-го класса школы №12 собрали 47 наборов, а сотрудники рязанского филиала «Сбербанка» — 83. Местный пекарь испёк 500 пряников в форме ёлочек и слоников — по одному к каждому подарку.\r\n\r\n«Я пришла с дочкой, — рассказывает жительница Октябрьского района Елена Воронина. — Мы купили книгу, тёплый шарф и игрушку для мальчика 10 лет. Дочь сама писала ему открытку: „Пусть твои мечты сбываются“. Это важнее, чем просто отдать коробку».\r\n\r\nПодарки были доставлены в детские дома №1 и №2, центр «Надежда» для детей с ДЦП и приют «Родник». Вручение прошло в формате небольшого праздника: с аниматорами, чаепитием и поздравлениями от Деда Мороза. Многие дети впервые получили подарок, адресованный именно им — по имени.\r\n\r\nАкция «Тепло на Рождество» продлится до 18 декабря: ещё можно принести вещи или средства. Все собранные деньги пойдут на покупку обуви для подростков — самый дефицитный пункт.\r\n\r\nКак помочь: • Принести игрушку, книгу, канцелярию или тёплую одежду в пункты сбора\r\n• Перевести средства на счёт благотворительного фонда «Доброе сердце»\r\n• Стать волонтёром — заполните анкету на buzz.ru/volunteer\r\nОрганизаторы надеются, что в следующем году акция станет ежегодной традицией, объединяющей весь город в заботе о самых уязвимых. Потому что, как говорят волонтёры: «Тепло создаётся не в домах — а в сердцах».\r\n\r\n«Наибольшая слава в жизни — не в том, чтобы никогда не падать,\r\nа в том, чтобы каждый раз подниматься».\r\nНельсон Мандела', '2025-12-17 08:32:30', '/uploads/69431ea0c8476.png'),
(7, 'ПРИРОДА СРЕДНЕРУССКОЙ НИЗМЕННОСТИ', 'КУЛЬТУРА', 'Дмитрий Козлов', 'Новая экспозиция в музее-заповеднике Есенина посвящена уникальной природе региона и включает живопись XIX века.', 'В Государственном музее-заповеднике С.А. Есенина в Константинове открылась новая экспозиция под названием «Природа Среднерусской низменности». Проект объединяет более 60 живописных и графических работ XIX — начала XX века, посвящённых уникальным ландшафтам Рязанского края.\r\n\r\nЦентральное место в выставке занимают полотна Фёдора Васильева, Исаака Левитана и Алексея Саврасова — художников, чьи работы сформировали поэтический образ русской природы. Особое внимание уделено мотиву «рязанской равнины» — открытого, бескрайнего пространства, пронизанного светом и тишиной.\r\n\r\n«Рязань — это не только поэзия Есенина, но и та природа, что его вдохновляла. Река Ока, туманные луга, тихие рощи — всё это живёт на холстах художников как визуальная поэма», — рассказывает куратор выставки Анна Петрова.\r\nПомимо классики, экспозиция включает редкие акварели местных художников начала XX века, а также современные фотографии тех же мест — в сопоставлении прошлого и настоящего. Например, пейзаж у села Шушлово 1887 года рядом с кадром, сделанным в 2025 году с той же точки.\r\n\r\nОсобый раздел посвящён реке Оке — её руслу, берегам и экосистеме. Здесь представлены не только картины, но и архивные карты, гербарии, аудиозаписи птиц, обитающих в долине Оки.\r\n\r\n«Мы хотели показать, что природа — это не просто фон, а действующее лицо истории, культуры и искусства Рязанского края», — добавляет куратор.\r\n\r\nВыставка будет работать до 28 февраля 2026 года. Вход — по билету музея. Для школьников и студентов — бесплатные экскурсии по предварительной записи.\r\n\r\nИнтересный факт:\r\nИменно в Рязанской губернии Исаак Левитан написал знаменитую «Над вечным покоем» — картина основана на пейзаже близ станции Плеханово на берегу Оки.\r\nОрганизаторы надеются, что экспозиция не только порадует ценителей искусства, но и напомнит: сохранение природного наследия — это часть культурной ответственности каждого из нас.\r\n\r\n«Художник должен любить природу не за её красоту, а за её правду».\r\nИсаак Левитан', '2025-12-17 13:11:44', '/uploads/69431c9092a19.png'),
(8, 'КОМАНДА «ЮНОСТЬ» ЗАВОЕВАЛА БРОНЗУ НА ЧР', 'СПОРТ', 'Алексей Волков', 'Воспитанники местной школы обыграли сборные Москвы и Нижнего Новгорода. Тренер: «Это только начало».', 'Юношеская баскетбольная команда «Юность» из Рязани завоевала бронзовые медали на Чемпионате России по баскетболу среди юношей до 16 лет. В матче за третье место рязанцы уверенно обыграли сборную Нижнего Новгорода со счётом 78:64.\r\n\r\nНа пути к бронзе команда также одержала сенсационную победу над московской «Спартой» в четвертьфинале — 72:70. Матч проходил в овертайме, а решающий трёхочковый бросок на последних секундах выполнил 15-летний Артём Соколов.\r\n\r\n«Это не просто медаль — это доказательство, что в Рязани растут настоящие баскетболисты. У нас нет мега-бюджета, но есть сердце, труд и вера. Это только начало», — сказал главный тренер «Юности» Михаил Дроздов.\r\nВ составе «Юности» — воспитанники Детско-юношеской спортивной школы №3. Все 12 игроков — учащиеся рязанских школ, некоторые совмещают тренировки с учёбой в лицее при РГУ.\r\n\r\nТурнир проходил в Казани с участием 24 команд со всей России. Победителем стала «ЦСКА-Юниор», серебро у «Локомотива-Юниор». Для Рязани же это — лучший результат за последние 15 лет.\r\n\r\nГородская администрация уже объявила, что команде выплатят премию, а школе — выделят средства на новое оборудование: мячи, стойки и форму.\r\n\r\nИнтересный факт:\r\nТренер команды Михаил Дроздов — бывший игрок «Рязань-ВДВ», а сегодня ещё и преподаёт физкультуру в школе №12.\r\n«Юность» вернулась в Рязань под овации на железнодорожном вокзале. Теперь ребят ждёт парад по центральной улице и встреча с главой региона. А впереди — участие в международном турнире в Минске в январе 2026 года.\r\n\r\n«Победа — это не результат. Победа — это то, что ты делаешь каждый день».\r\nМайкл Джордан', '2025-12-17 13:16:42', '/uploads/69431dba8a876.png'),
(9, 'ЗАПУСК ПРОИЗВОДСТВА ЭКО-УПАКОВОК', 'БИЗНЕС', 'Екатерина Морозова', 'Стартап получил грант от области и уже поставляет продукцию в 5 регионов. «Хочу, чтобы Рязань дышала чище».', 'На промышленной площадке в Рязани стартовало первое в регионе производство одноразовой упаковки из натурального льна и переработанной макулатуры. Проект реализован стартапом «GreenWrap» при поддержке Министерства экономического развития Рязанской области.\r\n\r\nУже через три месяца после запуска предприятие начало поставки в Москву, Тулу, Владимир, Тверь и Ярославль. Основные клиенты — кафе, крафтовые пекарни и курьерские службы, стремящиеся отказаться от пластика.\r\n\r\n«Я вырос в Рязани, где дышится легко. Но последние годы — всё иначе. Я не хочу, чтобы мои дети росли среди мусора. Хочу, чтобы Рязань дышала чище — и мы начинаем с малого: с упаковки для бургера», — говорит основатель «GreenWrap» Артём Лебедев.\r\nДля производства используется лён, выращенный в Скопинском районе, и вторсырьё от местных типографий. Готовая продукция — тарелки, стаканчики, контейнеры и пакеты — полностью биоразлагаема: разлагается за 45–90 дней в обычном компосте.\r\n\r\nСтартап получил грант в размере 8 млн рублей по программе «Инновации для устойчивого развития». Средства пошли на закупку оборудования из Финляндии и обучение персонала.\r\n\r\nНа предприятии уже трудятся 18 человек — преимущественно молодые рязанцы, вернувшиеся из крупных городов ради «работы с смыслом».\r\n\r\nИнтересный факт:\r\nПервую партию упаковки безвозмездно получили 30 рязанских социальных столовых и пункт выдачи помощи беженцам.\r\nВ 2026 году «GreenWrap» планирует выйти на экспорт — в Казахстан и Беларусь. А также запустить линию по переработке использованной упаковки обратно в сырьё — замыкая экологический цикл.\r\n\r\n«Бизнес будущего — это бизнес, который не вредит планете».\r\nПол Хокен', '2025-12-17 13:18:11', '/uploads/69431e8eedd6e.png'),
(10, '«ТЁПЛЫЕ ОКНА» ДЛЯ ОДИНОКИХ ПЕНСИОНЕРОВ', 'ОБЩЕСТВО', 'Анна Сидорова', 'Волонтёры Рязани бесплатно утепляют квартиры пожилых людей перед зимой. За месяц помощь получили уже 120 семей.', 'В этом году инициатива «Тёплые окна» впервые вышла за рамки благотворительной акции и стала системной программой поддержки. Команда из 30 волонтёров — студентов, строителей и просто неравнодушных горожан — каждые выходные ездит по адресам, присланным через соцсети и ТСЖ.\r\n\r\n«Многие пенсионеры экономят на отоплении, потому что боятся высоких счетов. Утепление окон — простая, но очень эффективная мера. Температура в комнате поднимается на 3–4 градуса», — рассказывает координатор проекта Ольга Кузнецова.\r\n\r\nВ этом году волонтёры не просто устанавливают уплотнители, но и обучают пожилых людей современным способам энергосбережения. А ещё — проверяют, всё ли в порядке с коммуникациями, и при необходимости вызывают специалистов.\r\n\r\n«Мы не просто ставим окна — мы заботимся о людях», — говорит 70-летняя Вера Ивановна из Октябрьского района. «Раньше я боялась зимы. Теперь знаю — обо мне не забыли».', '2025-12-17 14:31:09', '/uploads/69432f2d87f22.png'),
(11, 'БЕСПЛАТНЫЕ АВТОБУСЫ ДЛЯ ШКОЛЬНИКОВ', 'ОБЩЕСТВО', 'Екатерина Морозова', 'Город запустил пилотный проект по бесплатной перевозке учеников из Лесопаркового и Приокского районов.', 'С 1 сентября в Рязани стартовал проект «Безопасная дорога в школу». Два новых автобуса курсируют по фиксированным маршрутам, забирая детей из отдалённых микрорайонов и доставляя их к учебным заведениям к первому уроку.\r\n\r\n«Раньше дети 30 минут шли пешком — через лесопарк, где зимой почти нет освещения. Теперь они в безопасности», — поясняет начальник управления образования Рязани.\r\n\r\nПроект охватывает 5 школ и 3 лицея. В ближайшее время планируется расширить географию — в том числе, подключить сёла Рязанского района.\r\n\r\n«Это не просто транспорт, — говорит мама двух школьников, Анна Петрова. — Это уверенность, что дети придут вовремя и без стресса».', '2025-12-17 14:32:31', '/uploads/69432f7f04335.png'),
(12, 'КТО НАКОРМИТ БЕЗДОМНЫХ?', 'ОБЩЕСТВО', 'Иван Петров', 'Горожане организовали столовую, где каждый может получить горячий обед — без документов и вопросов.', 'На улице Свободы, в подвале бывшего ДК, уже три месяца работает «Кухня взаимопомощи». Инициативу запустили местные активисты, а поддержку оказали пекарня «Рязанская», ресторан «Ладья» и фермеры из Солотчи.\r\n\r\n«Мы не раздаём еду — мы делимся тем, что есть», — подчёркивает основательница проекта Мария Лебедева. Каждый день здесь бесплатно кормят до 80 человек: бездомных, пенсионеров, мигрантов, студентов.\r\n\r\nГотовят волонтёры. Моют посуду — те, кто пришёл поесть. Принимают помощь — продуктами, одеждой, лекарствами.\r\n\r\n«Здесь я не чувствую себя просителем, — рассказывает Алексей, который потерял работу полгода назад. — Я часть сообщества».', '2025-12-17 14:34:05', '/uploads/694331a3ae09a.png'),
(13, 'ПРИЛОЖЕНИЕ ДЛЯ ПОМОЩИ ПОЖИЛЫМ', 'ОБЩЕСТВО', 'Дмитрий Козлов', 'Молодёжь через мессенджер помогает бабушкам и дедушкам с покупками, лекарствами и бытовыми вопросами.', 'Приложение «Рядом» — это не очередной агрегатор услуг, а сообщество. Здесь молодые рязанцы сами записываются в «ангелы-хранители» и помогают пожилым соседям: сходят в аптеку, запишут к врачу, принесут продукты, настроят телевизор.\r\n\r\n«Многие пенсионеры боятся выходить из дома. А тут — живой человек, которому можно доверить ключи», — говорит разработчик, студент РГУ им. Есенина Алексей Волков.\r\n\r\nПроект стартовал в апреле и уже объединил более 400 волонтёров и 200 подопечных. Скоро появится функция «созвон» — чтобы бабушка могла просто поговорить с кем-то, пока готовит обед.', '2025-12-17 14:35:12', '/uploads/694331bb9836c.png'),
(14, 'ОТКРЫТ СЕЗОН СПЕКТАКЛЕЙ', 'КУЛЬТУРА', 'Анна Сидорова', 'Постановка «Письма к женщине» объединяет поэзию, современную хореографию и музыку группы «Наутилус».', 'Новый сезон в театре «Премьера» начинается с события. Спектакль «Письма к женщине» — это не просто биография Есенина, а попытка услышать современное эхо его чувств.\r\n\r\nНа сцене — живая музыка, танец и голос актёра, читающего подлинные письма поэта. В финале — проекция архивных кадров с улицами Рязани 1920-х.\r\n\r\n«Есенин — не музейный экспонат. Он — живой пульс города», — говорит режиссёр, Сергей Гришин.\r\n\r\nПремьера пройдёт 15 сентября. Билеты уже в продаже — как в кассе, так и через официальное приложение театра.', '2025-12-17 14:36:41', '/uploads/694331cfdc072.png'),
(15, '1155 ЛЕТ РЯЗАНИ: ЧТО СКРЫВАЕТ СОБОРНАЯ ГОРА', 'ИСТОРИЯ', 'Иван Петров', 'В 2025 году Рязань отмечает 1155-летие со дня основания. Археологи обнаружили фрагменты древних стен IX века.', 'На Соборной горе, где в 1237 году пала столица Рязанского княжества, археологи нашли укрепления, относящиеся к IX веку — на 200 лет раньше, чем считалось.\r\n\r\n«Это подтверждает: Рязань — один из старейших городов Руси, а не „молодая“ крепость», — рассказывает профессор РГУ им. Есенина Артём Соколов.\r\n\r\nВ честь юбилея на Соборной горе откроют мультимедийную экспозицию «Рязань: от крепости до мегаполиса». А в декабре пройдёт реконструкция обороны 1237 года — с участием исторических клубов из 12 регионов.', '2025-12-17 14:37:53', '/uploads/694330c1a7005.png'),
(16, 'ФЕСТИВАЛЬ ИСКУССТВА «СТЕНА ГОРОДА»', 'КУЛЬТУРА', 'Мария Лебедева', 'Художники из 12 регионов украсят глухие стены в центре Рязани — и проведут бесплатные мастер-классы.', 'С 10 по 17 августа в Рязани пройдёт фестиваль «Стена города». В центре внимания — муралы на тему «Лица Рязани». Участники будут изображать не только известных личностей (Есенина, Солженицына), но и обычных горожан: учителей, врачей, волонтёров.\r\n\r\nОсобое внимание — экологической теме. На одной из стен появится интерактивный мурал: при солнечном свете он будет «зеленеть», показывая, как растения очищают воздух.\r\n\r\nВсе желающие смогут принять участие в мастер-классах по стрит-арту, граффити и stencil’у. Фестиваль завершится ночным кинопоказом под открытым небом.', '2025-12-17 14:38:57', '/uploads/694331e5a70e3.png'),
(17, 'БИБЛИОТЕКА ПОД ОТКРЫТЫМ НЕБОМ В СОЛОТЧЕ', 'КУЛЬТУРА', 'Екатерина Морозова', 'В сквере у озера появилась зона с книгами, которые можно брать и оставлять без регистрации.', 'еперь после прогулки по Солотчинскому парку можно не только полюбоваться видами, но и взять книгу. В новом «Книжном дворике» — полки с классикой, детской литературой и современной прозой.\r\n\r\n«Принеси — возьми. Прочитал — оставь. Это цикл доверия», — говорит инициатор проекта, библиотекарь Елена Воронина.\r\n\r\nКаждую субботу здесь проходят встречи с писателями, поэтические чтения и «книжный обмен». А в дождь книги убирают в специальный чехол — так что фонд растёт, а не тонет.\r\n\r\n«Раньше читал дома. Теперь — под шум листьев и пение птиц. Это совсем другое ощущение», — делится читательница Анна Петрова.', '2025-12-17 14:40:42', '/uploads/6943316a6d6d4.png');

